class WordDictionary:
    def __init__(self):
        self.root = TrieNode()

    def addWord(self, word: str) -> None:
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end = True

    def search(self, word: str) -> bool:
        def dfs(node, i):
            if i == len(word):
                return node.is_end
            char = word[i]
            if char == '.':
                # try all children
                return any(dfs(child, i + 1) for child in node.children.values())
            else:
                if char not in node.children:
                    return False
                return dfs(node.children[char], i + 1)
        return dfs(self.root, 0)

class Solution:
    def findWords(self, board: list[list[str]], words: list[str]) -> list[str]:
        def dfs(r, c, word, i):
            if i == len(word):
                return True
            if r < 0 or r >= rows or c < 0 or c >= cols or board[r][c] != word[i]:
                return False
            tmp = board[r][c]
            board[r][c] = '#'  # mark visited
            found = (dfs(r+1, c, word, i+1) or dfs(r-1, c, word, i+1) or
                     dfs(r, c+1, word, i+1) or dfs(r, c-1, word, i+1))
            board[r][c] = tmp
            return found

        rows, cols = len(board), len(board[0])
        result = []
        for word in words:
            # try starting from every cell
            if any(dfs(r, c, word, 0) for r in range(rows) for c in range(cols)):
                result.append(word)
        return result

class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end = False
        self.word = None  # store the word here for easy collection

class Solution:
    def findWords(self, board: list[list[str]], words: list[str]) -> list[str]:
        # build trie
        root = TrieNode()
        for word in words:
            node = root
            for char in word:
                if char not in node.children:
                    node.children[char] = TrieNode()
                node = node.children[char]
            node.is_end = True
            node.word = word

        rows, cols = len(board), len(board[0])
        result = set()

        def dfs(r, c, node):
            char = board[r][c]
            if char not in node.children:
                return
            node = node.children[char]
            if node.is_end:
                result.add(node.word)  # found a word
                node.is_end = False    # avoid duplicates

            board[r][c] = '#'  # mark visited
            for dr, dc in [(1,0), (-1,0), (0,1), (0,-1)]:
                nr, nc = r + dr, c + dc
                if 0 <= nr < rows and 0 <= nc < cols and board[nr][nc] != '#':
                    dfs(nr, nc, node)
            board[r][c] = char  # restore

        for r in range(rows):
            for c in range(cols):
                dfs(r, c, root)
        return list(result)
